+    // Min should be 10ms
+    assert!((stats.min_ms - 10.0).abs() < 0.1, "min_ms was {}", stats.min_ms);
+
+    // Max should be 13ms
+    assert!((stats.max_ms - 13.0).abs() < 0.1, "max_ms was {}", stats.max_ms);
+
+    assert_eq!(stats.run_count, 5);
+
+    info!("test_timing_stats_calculations: passed");
